+        prop_assert!(!opt.selected);
+    }
+
+    #[test]
+    fn select_option_selected_toggle(
+        key in "[a-zA-Z]{1,10}",
+    ) {
+        let opt = SelectOption::new(key, 1).selected(true);
+        prop_assert!(opt.selected);
+
+        let opt2 = opt.selected(false);
+        prop_assert!(!opt2.selected);
+    }
+}
